<template>
  <div class="hello">
      <h1>xxpoxx's portfolio</h1>
        <router-link to="/profile"><div class="link_back"><div class="item"><div class="link">Profile</div></div></div></router-link>
        <router-link to="/works"><div class="link_back"><div class="item"><div class="link">Works</div></div></div></router-link>
  </div>
</template>

<script>
export default {
  name: 'main',
  data () {
    return {
      msg: 'Hello'
    }
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
.link {
  display: inline-block;
  width: max(10vw,100px);
  height: max(10vh,100px);
  background-color: #2c3e50;
  transition: all 0.3s linear 0s;
  color: rgb(255, 255, 255);
  line-height: 10vh;
}
.link_back {
  display: inline-block;
  width: max(10vw,100px);
  height: max(10vh,100px);
}
.link_back:hover .link {
  transform: rotateZ(360deg);
}
h1, h2 {
  font-weight: normal;
}
ul {
  list-style-type: none;
  padding: 0;
}
li {
  display: inline-block;
  margin: 0 10px;
}
a {
  color: #42b983;
}
.item{
  float: left;
  margin-right: 10px;
  padding: 10px;
  width: 60px;
  height: 60px;
  background: #EF5F5D;
  color: #fff;
  list-style: none;
  text-align: center;
  line-height: 60px;
  opacity: 0;
}

@mixin animationValue( $name, $duration , $function, $delay, $count, $state){
    -webkit-animation: $name $duration+s $function $delay+s $count $state;
  animation: $name $duration+s $function $delay+s $count $state;
}

@for $cnt from 1 through 6{
    .item:nth-child(#{$cnt}){
        @include animationValue(example, 0.5, ease, $cnt * 0.5 , 1, forwards);
    }
}

@mixin keyframes($name) {
  @-webkit-keyframes #{$name} {
    @content;
  }
  @keyframes #{$name} {
    @content;
  }
}

@include keyframes(example) {
  100% {
      opacity: 1;
  }
}
</style>



